  ('dietitian-moex-10754', 'dietitian', 'dietitian-moex-094-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '一種降血脂的藥物cholestyramine會影響膽酸的活性，因此可能會影響下列何種營養素的吸收？', '["醣類", "蛋白質", "脂溶性維生素", "水溶性維生素"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "3e329c29ee43", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094130", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "094", "exam_name": "094年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
